41: func notAuthorized(c *contextmodel.ReqContext) {
42: 	if c.IsApiRequest() {
43: 		c.WriteErrOrFallback(http.StatusUnauthorized, http.StatusText(http.StatusUnauthorized), c.LookupTokenErr)
44: 		return
45: 	}
46: 
47: 	if !c.UseSessionStorageRedirect {
48: 		writeRedirectCookie(c)
49: 	}
50: 
51: 	var tokenRotationErr authn.TokenNeedsRotationError
52: 	if errors.As(c.LookupTokenErr, &tokenRotationErr) {
53: 		if !c.UseSessionStorageRedirect {
54: 			c.Redirect(setting.AppSubUrl + "/user/auth-tokens/rotate")
55: 			return
56: 		}
57: 
58: 		c.Redirect(setting.AppSubUrl + "/user/auth-tokens/rotate" + getRedirectToQueryParam(c))
59: 		return
60: 	}
61: 
62: 	if !c.UseSessionStorageRedirect {
63: 		c.Redirect(setting.AppSubUrl + "/login")
64: 		return
65: 	}
66: 
67: 	c.Redirect(setting.AppSubUrl + "/login" + getRedirectToQueryParam(c))
68: }
