70: func tokenRevoked(c *contextmodel.ReqContext, err *auth.TokenRevokedError) {
71: 	if c.IsApiRequest() {
72: 		c.JSON(http.StatusUnauthorized, map[string]any{
73: 			"message": "Token revoked",
74: 			"error": map[string]any{
75: 				"id":                    "ERR_TOKEN_REVOKED",
76: 				"maxConcurrentSessions": err.MaxConcurrentSessions,
77: 			},
78: 		})
79: 		return
80: 	}
81: 
82: 	if !c.UseSessionStorageRedirect {
83: 		writeRedirectCookie(c)
84: 		c.Redirect(setting.AppSubUrl + "/login")
85: 		return
86: 	}
87: 
88: 	c.Redirect(setting.AppSubUrl + "/login" + getRedirectToQueryParam(c))
89: }
