91: func writeRedirectCookie(c *contextmodel.ReqContext) {
92: 	redirectTo := c.Req.RequestURI
93: 	if setting.AppSubUrl != "" && !strings.HasPrefix(redirectTo, setting.AppSubUrl) {
94: 		redirectTo = setting.AppSubUrl + c.Req.RequestURI
95: 	}
96: 
97: 	if redirectTo == "/" {
98: 		return
99: 	}
100: 
101: 	// remove any forceLogin=true params
102: 	redirectTo = RemoveForceLoginParams(redirectTo)
103: 	cookies.WriteCookie(c.Resp, "redirect_to", url.QueryEscape(redirectTo), 0, nil)
104: }
