127: func CanAdminPlugins(cfg *setting.Cfg, accessControl ac.AccessControl) func(c *contextmodel.ReqContext) {
128: 	return func(c *contextmodel.ReqContext) {
129: 		hasAccess := ac.HasAccess(accessControl, c)
130: 		if !pluginaccesscontrol.ReqCanAdminPlugins(cfg)(c) && !hasAccess(pluginaccesscontrol.AdminAccessEvaluator) {
131: 			accessForbidden(c)
132: 			return
133: 		}
134: 		if c.AllowAnonymous && !c.IsSignedIn && shouldForceLogin(c) {
135: 			notAuthorized(c)
136: 			return
137: 		}
138: 	}
139: }
