187: func RoleAuth(roles ...org.RoleType) web.Handler {
188: 	return func(c *contextmodel.ReqContext) {
189: 		ok := false
190: 		for _, role := range roles {
191: 			if role == c.OrgRole {
192: 				ok = true
193: 				break
194: 			}
195: 		}
196: 		if !ok {
197: 			accessForbidden(c)
198: 		}
199: 	}
200: }
